    for(int i = 0; i < n; i++) {
        mean += arr[i];
    }
    mean /= n; // calculate mean

    for(int i = 0; i < n; i++) {
        var += pow(arr[i] - mean, 2);
    }
    var /= n; // calculate variance

    double std_dev = sqrt(var); // standard deviation

    double x_min = mean - 4 * std_dev; // minimum x-value to display
    double x_max = mean + 4 * std_dev; // maximum x-value to display
    double x_step = (x_max - x_min) / WIDTH; // x increment
    double y_step = 3.0 / HEIGHT; // y increment

    for(int i = 0; i < HEIGHT; i++) {
        double y = 1.5 - i * y_step; // y value to display
        for(int j = 0; j < WIDTH; j++) {
